body.script:
//
(function () {
    'use strict';

    const TOKEN   = _DSP_TOKEN;
    const API_URL = '/antrian/' + TOKEN + '/data';
    const HARI    = ['Minggu','Senin','Selasa','Rabu','Kamis','Jumat','Sabtu'];
    const BULAN   = ['Januari','Februari','Maret','April','Mei','Juni',
                     'Juli','Agustus','September','Oktober','November','Desember'];
    const INTERVAL = 5000;

    /* ── Clock ─────────────────────────────────────────────────────────────── */

    function pad(n) { return String(n).padStart(2, '0'); }

    function tickClock() {
        const now = new Date();
        document.getElementById('dsp-clock').textContent =
            pad(now.getHours()) + ':' + pad(now.getMinutes()) + ':' + pad(now.getSeconds());
        document.getElementById('dsp-date').textContent =
            HARI[now.getDay()] + ', ' + now.getDate() + ' ' + BULAN[now.getMonth()] + ' ' + now.getFullYear();
    }
    setInterval(tickClock, 1000);
    tickClock();

    /* ── Helpers ────────────────────────────────────────────────────────────── */

    function esc(s) {
        return String(s || '')
            .replace(/&/g,  '&amp;')
            .replace(/</g,  '&lt;')
            .replace(/>/g,  '&gt;')
            .replace(/"/g,  '&quot;');
    }

    /* ── Render ─────────────────────────────────────────────────────────────── */

    function renderGrid(lokets) {
        const grid = document.getElementById('dsp-grid');

        if (!lokets || !lokets.length) {
            grid.innerHTML =
                '<div class="dsp-empty">' +
                    '<div class="dsp-empty-icon">📋</div>' +
                    '<div class="dsp-empty-text">Tidak ada loket aktif hari ini</div>' +
                '</div>';
            return;
        }

        /* Rebuild DOM hanya jika jumlah loket berubah (hindari flicker) */
        const existing = grid.querySelectorAll('.dsp-card');
        if (existing.length !== lokets.length) {
            grid.innerHTML = '';
            lokets.forEach(() => {
                const card = document.createElement('div');
                card.className = 'dsp-card';
                card.innerHTML =
                    '<div class="dsp-card-header">' +
                        '<div class="dsp-loket-name"></div>' +
                        '<div class="dsp-layanan-name"></div>' +
                    '</div>' +
                    '<div class="dsp-card-body">' +
                        '<div class="dsp-label">Sedang Dilayani</div>' +
                        '<div class="dsp-number-box">' +
                            '<div class="dsp-number empty">KOSONG</div>' +
                            '<div class="dsp-number-name"></div>' +
                        '</div>' +
                        '<div class="dsp-sep"></div>' +
                        '<div class="dsp-label dsp-label--wait">Menunggu Berikutnya</div>' +
                        '<div class="dsp-waiting-pills"></div>' +
                    '</div>';
                grid.appendChild(card);
            });
        }

        const cards = grid.querySelectorAll('.dsp-card');
        lokets.forEach(function (loket, i) {
            const card     = cards[i];
            const dipanggil = loket.dipanggil || [];
            const menunggu  = loket.menunggu  || [];

            /* Header */
            card.querySelector('.dsp-loket-name').textContent   = loket.loket   || '';
            card.querySelector('.dsp-layanan-name').textContent = loket.layanan || '';

            /* Current number */
            const hasNum = dipanggil.length > 0;
            const numEl  = card.querySelector('.dsp-number');
            const nameEl = card.querySelector('.dsp-number-name');
            const boxEl  = card.querySelector('.dsp-number-box');

            if (hasNum) {
                numEl.textContent  = dipanggil[0].nomor;
                nameEl.textContent = dipanggil[0].nama || '';
                numEl.className    = 'dsp-number active';
            } else {
                numEl.textContent  = 'KOSONG';
                nameEl.textContent = '';
                numEl.className    = 'dsp-number empty';
            }
            nameEl.className = 'dsp-number-name' + (hasNum ? ' active' : '');
            boxEl.className  = 'dsp-number-box'  + (hasNum ? ' has-number' : '');
            card.className   = 'dsp-card'        + (hasNum ? ' active' : '');

            /* Waiting count badge on label */
            const waitLabel = card.querySelector('.dsp-label--wait');
            if (waitLabel) {
                const badgeHtml = menunggu.length
                    ? ' <span class="dsp-count-badge">' + menunggu.length + '</span>'
                    : '';
                waitLabel.innerHTML = 'Menunggu Berikutnya' + badgeHtml;
            }

            /* Waiting pills */
            const pillsEl = card.querySelector('.dsp-waiting-pills');
            if (menunggu.length) {
                pillsEl.innerHTML = menunggu.map(function (a) {
                    return '<span class="dsp-pill">' + esc(a.nomor) + '</span>';
                }).join('');
            } else {
                pillsEl.innerHTML = '<span class="dsp-no-waiting">Tidak ada antrian</span>';
            }
        });
    }

    /* ── Fetch ──────────────────────────────────────────────────────────────── */

    function setStatus(ok, msg) {
        const dot  = document.getElementById('dsp-dot');
        const text = document.getElementById('dsp-status-text');
        dot.className  = 'dsp-dot' + (ok ? '' : ' error');
        text.textContent = msg;
    }

    async function fetchData() {
        try {
            const resp = await fetch(API_URL, { method: 'GET', cache: 'no-store' });
            if (!resp.ok) throw new Error('HTTP ' + resp.status);
            const data = await resp.json();
            if (data.error) throw new Error(data.error);

            renderGrid(data.lokets);
            setStatus(true, 'Terhubung — update setiap 5 detik');

            const now = new Date();
            document.getElementById('dsp-updated').textContent =
                'Diperbarui: ' + pad(now.getHours()) + ':' + pad(now.getMinutes()) + ':' + pad(now.getSeconds());
        } catch (e) {
            setStatus(false, 'Koneksi terputus — mencoba ulang...');
        }
    }

    fetchData();
    setInterval(fetchData, INTERVAL);
})();
//
